#include <stdio.h>
#include <stdlib.h>

typedef long long ll;

typedef struct {
    int u, v, w;
} Edge;

/* ---------- DSU ---------- */

int find(int parent[], int x) {
    while (parent[x] != x) {
        parent[x] = parent[parent[x]];  // path compression
        x = parent[x];
    }
    return x;
}

int unite(int parent[], int a, int b) {
    int pa = find(parent, a);
    int pb = find(parent, b);
    if (pa == pb) return 0;
    parent[pa] = pb;
    return 1;
}

/* ---------- Comparator for qsort ---------- */

int cmp(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    if (e1->w < e2->w) return -1;
    if (e1->w > e2->w) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);

        char kinds[N + 5];
        scanf("%s", kinds);

        Edge *edges = (Edge *)malloc(sizeof(Edge) * M);

        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);
            edges[i].u--;  // 0-based
            edges[i].v--;
        }

        /* Sort edges by weight */
        qsort(edges, M, sizeof(Edge), cmp);

        int *parent = (int *)malloc(sizeof(int) * N);
        for (int i = 0; i < N; i++)
            parent[i] = i;

        ll res = 0;

        /* Connect all restaurants first (cost 0) */
        int firstR = -1;
        for (int i = 0; i < N; i++) {
            if (kinds[i] == 'R') {
                firstR = i;
                break;
            }
        }

        for (int i = firstR + 1; i < N; i++) {
            if (kinds[i] == 'R') {
                unite(parent, firstR, i);
            }
        }

        /* Modified Kruskal */
        for (int i = 0; i < M; i++) {
            int u = edges[i].u;
            int v = edges[i].v;
            int w = edges[i].w;

            if (w <= 0) {
                res += w;
                unite(parent, u, v);
            } else {
                if (find(parent, u) != find(parent, v)) {
                    res += w;
                    unite(parent, u, v);
                }
            }
        }

        printf("%lld\n", res);

        free(edges);
        free(parent);
    }

    return 0;
}

