import java.io.*;
import java.util.*;

public class Main {

    // Fast Scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;

        FastScanner(InputStream is) {
            in = is;
        }

        private int read() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }

        int nextInt() throws IOException {
            int c, s = 1, x = 0;
            while ((c = read()) <= ' ') if (c == -1) return -1;
            if (c == '-') {
                s = -1;
                c = read();
            }
            while (c > ' ') {
                x = x * 10 + c - '0';
                c = read();
            }
            return x * s;
        }

        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = read()) <= ' ') if (c == -1) return "";
            while (c > ' ') {
                sb.append((char) c);
                c = read();
            }
            return sb.toString();
        }
    }

    static int find(int[] parent, int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]]; // path compression
            x = parent[x];
        }
        return x;
    }

    static boolean union(int[] parent, int a, int b) {
        int pa = find(parent, a);
        int pb = find(parent, b);
        if (pa == pb) return false;
        parent[pa] = pb;
        return true;
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();

        int T = fs.nextInt();
        while (T-- > 0) {

            int N = fs.nextInt();
            int M = fs.nextInt();
            String kinds = fs.next();

            int[][] edges = new int[M][3];

            for (int i = 0; i < M; i++) {
                edges[i][0] = fs.nextInt() - 1;
                edges[i][1] = fs.nextInt() - 1;
                edges[i][2] = fs.nextInt();
            }

            // Sort by weight
            Arrays.sort(edges, Comparator.comparingInt(a -> a[2]));

            int[] parent = new int[N];
            for (int i = 0; i < N; i++) parent[i] = i;

            long res = 0;

            // Connect all restaurants first (cost 0)
            int firstR = -1;
            for (int i = 0; i < N; i++) {
                if (kinds.charAt(i) == 'R') {
                    firstR = i;
                    break;
                }
            }

            for (int i = firstR + 1; i < N; i++) {
                if (kinds.charAt(i) == 'R') {
                    union(parent, firstR, i);
                }
            }

            // Modified Kruskal
            for (int i = 0; i < M; i++) {
                int u = edges[i][0];
                int v = edges[i][1];
                int w = edges[i][2];

                if (w <= 0) {
                    res += w;
                    union(parent, u, v);
                } else {
                    if (find(parent, u) != find(parent, v)) {
                        res += w;
                        union(parent, u, v);
                    }
                }
            }

            out.append(res).append('\n');
        }

        System.out.print(out);
    }
}
